ph.disp:
{nights(), plural,
              =1 {1 noc}
              few {{{ nights() }} noci}
              other {{{ nights() }} nocí}
            }

{c.qty, plural,
                  =1 {1 chatka rezervována}
                  few {{{ c.qty }} chatky rezervovány}
                  other {{{ c.qty }} chatek rezervováno}
                }
